# ROBUSTNESS PHASE B — Extended protocol correctness tests
# Manually written, not generated by testgen.py. Do not delete.
#
# Covers service edge cases not exercised by the generated test suite:
# RDBI session-gate NRC, RoutineControl start/results state, missing
# CommunicationControl and ControlDTCSetting implementations, session
# control boundaries, ECUReset state propagation.
#
# Run: pytest test_robustness_B_protocol.py -v --can-interface=simulator
from __future__ import annotations

import pytest
from conftest import (
    _InlineEcuState, _inline_handle,
    SESSION_DEFAULT, SESSION_EXTENDED, SESSION_PROGRAMMING,
    NRC_INCORRECT_MSG_LEN, NRC_CONDITIONS_NOT_CORRECT,
    NRC_REQUEST_OUT_OF_RANGE, NRC_SECURITY_ACCESS_DENIED,
    NRC_INVALID_KEY, NRC_SUB_FUNCTION_NOT_SUPPORTED,
    NRC_SERVICE_NOT_SUPPORTED_IN_SESSION,
    SID_DIAGNOSTIC_SESSION_CONTROL, SID_ECU_RESET,
    SID_READ_DATA_BY_ID, SID_WRITE_DATA_BY_ID,
    SID_ROUTINE_CONTROL, SID_TESTER_PRESENT,
    SID_NEGATIVE_RESPONSE, POSITIVE_RESPONSE_OFFSET,
)

# Additional SIDs not in conftest constants
SID_COMM_CONTROL    = 0x28
SID_CONTROL_DTC     = 0x85
SID_CLEAR_DTC       = 0x14
SID_READ_DTC        = 0x19

# DID IDs from basic_ecu config (hex → int)
DID_VIN            = 0xF190  # read, default session, no security
DID_SERIAL         = 0xF18C  # read, default session, no security
DID_SPARE_PART     = 0xF187  # read+write, extended session, write_sec=1
DID_ENGINE_SPEED   = 0x0C00  # read, default session, no security
DID_COOLANT_TEMP   = 0x0500  # read, default session, no security
DID_UNKNOWN        = 0xDEAD  # does not exist in config

# Routine IDs
RID_SELF_TEST      = 0xFF00  # extended session, no security, support: start+results
RID_FACTORY_RESET  = 0xFF01  # extended session, security_level=1, support: start
RID_ERASE_NVM      = 0xFF10  # programming session, security_level=1, support: start+results
RID_UNKNOWN        = 0x1234  # does not exist


def _sim():
    """Fresh inline ECU simulator state."""
    return _InlineEcuState()


def _req(state: _InlineEcuState, pdu: bytes) -> bytes | None:
    return _inline_handle(pdu, state, False)


def _session(state: _InlineEcuState, sub: int) -> None:
    _req(state, bytes([SID_DIAGNOSTIC_SESSION_CONTROL, sub]))


def _nrc(sid, code):
    return bytes([SID_NEGATIVE_RESPONSE, sid, code])


class TestRDBISessionAndSecurityGates:
    """RDBI must return NRC 0x7F for session violations (not 0x31)."""

    def test_rdbi_session_gate_returns_nrc_7f_not_31(self):
        """DID 0xF187 requires extended session; reading in default should return 0x7F."""
        state = _sim()
        # In default session
        resp = _req(state, bytes([SID_READ_DATA_BY_ID,
                                   (DID_SPARE_PART >> 8) & 0xFF,
                                    DID_SPARE_PART & 0xFF]))
        assert resp is not None
        assert resp[0] == SID_NEGATIVE_RESPONSE, f"Expected NRC, got {resp.hex()}"
        assert resp[1] == SID_READ_DATA_BY_ID
        assert resp[2] == NRC_SERVICE_NOT_SUPPORTED_IN_SESSION, (
            f"ASIL-B step 2 must return NRC 0x7F for session gate, "
            f"got NRC 0x{resp[2]:02X} — this is the same bug pattern as WDBI "
            f"(was returning 0x31 requestOutOfRange instead of 0x7F)")

    def test_rdbi_session_gate_after_upgrade_allows_access(self):
        """Same DID 0xF187 must be readable after upgrading to extended session."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        resp = _req(state, bytes([SID_READ_DATA_BY_ID,
                                   (DID_SPARE_PART >> 8) & 0xFF,
                                    DID_SPARE_PART & 0xFF]))
        assert resp is not None and resp[0] == SID_READ_DATA_BY_ID + POSITIVE_RESPONSE_OFFSET

    def test_rdbi_security_gate_returns_nrc_33(self):
        """Read-protected DID without security unlock → NRC 0x33."""
        # First we need a DID with read_security_level > 0. The basic_ecu config doesn't
        # have one in the read direction, so let's verify existing behavior: security
        # unlocked DIDs in extended session are accessible without unlock (read_sec=0).
        state = _sim()
        _session(state, SESSION_EXTENDED)
        resp = _req(state, bytes([SID_READ_DATA_BY_ID,
                                   (DID_SPARE_PART >> 8) & 0xFF,
                                    DID_SPARE_PART & 0xFF]))
        assert resp is not None and resp[0] == SID_READ_DATA_BY_ID + POSITIVE_RESPONSE_OFFSET, (
            "F187 has read_security_level=0, should be readable in extended without unlock")

    def test_rdbi_unknown_did_returns_nrc_31(self):
        state = _sim()
        resp = _req(state, bytes([SID_READ_DATA_BY_ID,
                                   (DID_UNKNOWN >> 8) & 0xFF,
                                    DID_UNKNOWN & 0xFF]))
        assert resp == _nrc(SID_READ_DATA_BY_ID, NRC_REQUEST_OUT_OF_RANGE)

    def test_rdbi_single_byte_pdu_returns_nrc_13(self):
        state = _sim()
        resp = _req(state, bytes([SID_READ_DATA_BY_ID]))
        assert resp == _nrc(SID_READ_DATA_BY_ID, NRC_INCORRECT_MSG_LEN)

    def test_rdbi_odd_length_multi_did_returns_nrc_13(self):
        """Multi-DID request with odd total length (not aligned to 2-byte DID pairs)."""
        state = _sim()
        resp = _req(state, bytes([SID_READ_DATA_BY_ID, 0xF1, 0x90, 0xF1]))  # 3 bytes after SID
        assert resp == _nrc(SID_READ_DATA_BY_ID, NRC_INCORRECT_MSG_LEN)

    def test_rdbi_default_value_before_write_is_nonzero(self):
        """Inline simulator pre-fills DIDs with 0xAA. Read before write returns 0xAA bytes."""
        state = _sim()
        resp = _req(state, bytes([SID_READ_DATA_BY_ID,
                                   (DID_VIN >> 8) & 0xFF,
                                    DID_VIN & 0xFF]))
        assert resp is not None and resp[0] == SID_READ_DATA_BY_ID + POSITIVE_RESPONSE_OFFSET
        payload = resp[3:]  # after 0x62 + DID bytes
        assert all(b == 0xAA for b in payload), "Pre-filled default should be 0xAA"
        assert len(payload) == 17


class TestRoutineControlStateTracking:
    """RoutineControl must track started/stopped state — results before start → NRC 0x22."""

    def test_rc_results_before_start_returns_nrc_22(self):
        """ISO 14229-1: requestResults (0x03) before startRoutine (0x01) → NRC 0x22."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        resp = _req(state, bytes([SID_ROUTINE_CONTROL, 0x03,
                                   (RID_SELF_TEST >> 8) & 0xFF,
                                    RID_SELF_TEST & 0xFF]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE, (
            f"Expected NRC for results-before-start, got positive: {resp.hex()}")
        assert resp[2] == NRC_CONDITIONS_NOT_CORRECT, (
            f"ISO 14229-1 requires NRC 0x22 (conditionsNotCorrect) for requestResults "
            f"before startRoutine, got NRC 0x{resp[2]:02X}")

    def test_rc_start_then_results_returns_positive(self):
        state = _sim()
        _session(state, SESSION_EXTENDED)
        start_resp = _req(state, bytes([SID_ROUTINE_CONTROL, 0x01,
                                        (RID_SELF_TEST >> 8) & 0xFF,
                                         RID_SELF_TEST & 0xFF]))
        assert start_resp is not None
        assert start_resp[0] == SID_ROUTINE_CONTROL + POSITIVE_RESPONSE_OFFSET
        results_resp = _req(state, bytes([SID_ROUTINE_CONTROL, 0x03,
                                          (RID_SELF_TEST >> 8) & 0xFF,
                                           RID_SELF_TEST & 0xFF]))
        assert results_resp is not None
        assert results_resp[0] == SID_ROUTINE_CONTROL + POSITIVE_RESPONSE_OFFSET

    def test_rc_stop_before_start_returns_nrc_22(self):
        """stopRoutine (0x02) before startRoutine → NRC 0x22."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        # FF00 supports start+results but not stop — but even if it did, stop before start is invalid
        # Use a hypothetical routine that supports stop; since FF00 doesn't have stop, check NRC 0x12
        resp = _req(state, bytes([SID_ROUTINE_CONTROL, 0x02,
                                   (RID_SELF_TEST >> 8) & 0xFF,
                                    RID_SELF_TEST & 0xFF]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE, (
            "Stop on routine with no 'stop' support must return NRC")
        # 0x12 = subFunctionNotSupported (routine doesn't support stop)
        assert resp[2] == NRC_SUB_FUNCTION_NOT_SUPPORTED, (
            f"Routine without 'stop' support should return NRC 0x12, got 0x{resp[2]:02X}")

    def test_rc_results_without_support_returns_nrc_12(self):
        """FF01 supports only 'start', not 'results'. Requesting results → NRC 0x12."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        state.sec_unlocked[1] = True  # bypass security to test the support-check layer
        resp = _req(state, bytes([SID_ROUTINE_CONTROL, 0x03,
                                   (RID_FACTORY_RESET >> 8) & 0xFF,
                                    RID_FACTORY_RESET & 0xFF]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_SUB_FUNCTION_NOT_SUPPORTED

    def test_rc_unknown_routine_returns_nrc_31(self):
        state = _sim()
        _session(state, SESSION_EXTENDED)
        resp = _req(state, bytes([SID_ROUTINE_CONTROL, 0x01,
                                   (RID_UNKNOWN >> 8) & 0xFF,
                                    RID_UNKNOWN & 0xFF]))
        assert resp == _nrc(SID_ROUTINE_CONTROL, NRC_REQUEST_OUT_OF_RANGE)

    def test_rc_invalid_subfunction_0x00_returns_nrc_12(self):
        state = _sim()
        _session(state, SESSION_EXTENDED)
        resp = _req(state, bytes([SID_ROUTINE_CONTROL, 0x00,
                                   (RID_SELF_TEST >> 8) & 0xFF,
                                    RID_SELF_TEST & 0xFF]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_SUB_FUNCTION_NOT_SUPPORTED

    def test_rc_invalid_subfunction_0x04_returns_nrc_12(self):
        state = _sim()
        _session(state, SESSION_EXTENDED)
        resp = _req(state, bytes([SID_ROUTINE_CONTROL, 0x04,
                                   (RID_SELF_TEST >> 8) & 0xFF,
                                    RID_SELF_TEST & 0xFF]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_SUB_FUNCTION_NOT_SUPPORTED

    def test_rc_session_gate_returns_nrc_7f(self):
        """Routine in extended session, requested in default → NRC 0x7F."""
        state = _sim()
        resp = _req(state, bytes([SID_ROUTINE_CONTROL, 0x01,
                                   (RID_SELF_TEST >> 8) & 0xFF,
                                    RID_SELF_TEST & 0xFF]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_SERVICE_NOT_SUPPORTED_IN_SESSION

    def test_rc_too_short_pdu_returns_nrc_13(self):
        state = _sim()
        _session(state, SESSION_EXTENDED)
        resp = _req(state, bytes([SID_ROUTINE_CONTROL, 0x01, 0xFF]))  # missing second RID byte
        assert resp == _nrc(SID_ROUTINE_CONTROL, NRC_INCORRECT_MSG_LEN)


class TestMissingServicesImplementation:
    """CommunicationControl (0x28) and ControlDTCSetting (0x85) must not return NRC 0x11."""

    def test_comm_control_in_default_returns_session_nrc(self):
        """0x28 in default session should return NRC 0x7F (not 0x11 serviceNotSupported)."""
        state = _sim()
        resp = _req(state, bytes([SID_COMM_CONTROL, 0x03, 0x01]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE, (
            f"Expected NRC for 0x28 in default, got {resp.hex() if resp else None}")
        assert resp[2] != 0x11, (
            f"NRC 0x11 (serviceNotSupported) means 0x28 is completely unimplemented. "
            f"CommunicationControl must at minimum return NRC 0x7F in default session. "
            f"Got NRC 0x{resp[2]:02X}")

    def test_comm_control_in_extended_returns_valid_response(self):
        """0x28 in extended session should return positive or a meaningful NRC (not 0x11)."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        resp = _req(state, bytes([SID_COMM_CONTROL, 0x03, 0x01]))
        assert resp is not None, "0x28 in extended session must not time out"
        if resp[0] == SID_NEGATIVE_RESPONSE:
            assert resp[2] != 0x11, (
                f"NRC 0x11 means service unimplemented; 0x28 must be handled in extended. "
                f"Got NRC 0x{resp[2]:02X}")
        else:
            assert resp[0] == SID_COMM_CONTROL + POSITIVE_RESPONSE_OFFSET

    def test_control_dtc_setting_in_default_returns_session_nrc(self):
        """0x85 in default session should return NRC 0x7F (not 0x11)."""
        state = _sim()
        resp = _req(state, bytes([SID_CONTROL_DTC, 0x01]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] != 0x11, (
            f"NRC 0x11 means 0x85 is unimplemented. ControlDTCSetting must return "
            f"NRC 0x7F in default session. Got NRC 0x{resp[2]:02X}")

    def test_control_dtc_setting_in_extended_returns_valid_response(self):
        """0x85 in extended session should work or return meaningful NRC."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        resp = _req(state, bytes([SID_CONTROL_DTC, 0x01]))
        assert resp is not None
        if resp[0] == SID_NEGATIVE_RESPONSE:
            assert resp[2] != 0x11, (
                f"NRC 0x11 means 0x85 completely unimplemented. Got NRC 0x{resp[2]:02X}")
        else:
            assert resp[0] == SID_CONTROL_DTC + POSITIVE_RESPONSE_OFFSET


class TestClearDiagnosticInformationSession:
    """ClearDiagnosticInformation (0x14) must enforce extended session requirement."""

    def test_clear_dtc_in_default_session_rejected(self):
        """ISO 14229-1: ClearDTC requires extended session. Default → NRC 0x7F."""
        state = _sim()
        # Set a DTC first
        state.dtcs[0]['status'] = 0x08
        resp = _req(state, bytes([SID_CLEAR_DTC, 0xFF, 0xFF, 0xFF]))
        assert resp is not None
        # Correct behavior: NRC 0x7F in default session
        if resp[0] == SID_CLEAR_DTC + POSITIVE_RESPONSE_OFFSET:
            pytest.fail(
                "ClearDiagnosticInformation (0x14) accepted in default session — "
                "ISO 14229-1 requires extended session. NRC 0x7F should be returned.")
        assert resp[2] == NRC_SERVICE_NOT_SUPPORTED_IN_SESSION, (
            f"Expected NRC 0x7F for ClearDTC in default session, got NRC 0x{resp[2]:02X}")

    def test_clear_dtc_in_extended_session_accepted(self):
        """After session upgrade to extended, ClearDTC must work."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        resp = _req(state, bytes([SID_CLEAR_DTC, 0xFF, 0xFF, 0xFF]))
        assert resp is not None and resp[0] == SID_CLEAR_DTC + POSITIVE_RESPONSE_OFFSET


class TestDiagnosticSessionControl:
    """Session transitions, invalid subfunctions, suppress-response bit."""

    def test_all_valid_sessions_reachable(self):
        state = _sim()
        for sub in (SESSION_DEFAULT, SESSION_EXTENDED, SESSION_PROGRAMMING, SESSION_DEFAULT):
            resp = _req(state, bytes([SID_DIAGNOSTIC_SESSION_CONTROL, sub]))
            assert resp is not None and resp[0] == SID_DIAGNOSTIC_SESSION_CONTROL + POSITIVE_RESPONSE_OFFSET

    def test_invalid_session_0x00_returns_nrc_12(self):
        state = _sim()
        resp = _req(state, bytes([SID_DIAGNOSTIC_SESSION_CONTROL, 0x00]))
        assert resp == _nrc(SID_DIAGNOSTIC_SESSION_CONTROL, NRC_SUB_FUNCTION_NOT_SUPPORTED)

    def test_invalid_session_0x04_returns_nrc_12(self):
        state = _sim()
        resp = _req(state, bytes([SID_DIAGNOSTIC_SESSION_CONTROL, 0x04]))
        assert resp == _nrc(SID_DIAGNOSTIC_SESSION_CONTROL, NRC_SUB_FUNCTION_NOT_SUPPORTED)

    def test_session_response_contains_timing_parameters(self):
        state = _sim()
        resp = _req(state, bytes([SID_DIAGNOSTIC_SESSION_CONTROL, SESSION_EXTENDED]))
        assert resp is not None and len(resp) == 6, (
            f"DSC positive response must be 6 bytes [0x50, sub, p2hi, p2lo, p2shi, p2slo], "
            f"got {resp.hex()}")

    def test_session_suppress_response_bit(self):
        state = _sim()
        resp = _req(state, bytes([SID_DIAGNOSTIC_SESSION_CONTROL, SESSION_EXTENDED | 0x80]))
        assert resp is None, "Suppress-response bit (0x80) must produce no response"

    def test_session_too_short_pdu_nrc_13(self):
        state = _sim()
        resp = _req(state, bytes([SID_DIAGNOSTIC_SESSION_CONTROL]))
        assert resp == _nrc(SID_DIAGNOSTIC_SESSION_CONTROL, NRC_INCORRECT_MSG_LEN)


class TestECUResetBehavior:
    """ECUReset must reset session to default and handle all valid subfunctions."""

    def test_ecu_reset_hardreset_returns_0x51_0x01(self):
        state = _sim()
        resp = _req(state, bytes([SID_ECU_RESET, 0x01]))
        assert resp == bytes([SID_ECU_RESET + POSITIVE_RESPONSE_OFFSET, 0x01])

    def test_ecu_reset_key_cycle_returns_0x51_0x02(self):
        state = _sim()
        resp = _req(state, bytes([SID_ECU_RESET, 0x02]))
        assert resp == bytes([SID_ECU_RESET + POSITIVE_RESPONSE_OFFSET, 0x02])

    def test_ecu_reset_softreset_returns_0x51_0x03(self):
        state = _sim()
        resp = _req(state, bytes([SID_ECU_RESET, 0x03]))
        assert resp == bytes([SID_ECU_RESET + POSITIVE_RESPONSE_OFFSET, 0x03])

    def test_ecu_reset_invalid_sub_0x00_returns_nrc_12(self):
        state = _sim()
        resp = _req(state, bytes([SID_ECU_RESET, 0x00]))
        assert resp == _nrc(SID_ECU_RESET, NRC_SUB_FUNCTION_NOT_SUPPORTED)

    def test_ecu_reset_invalid_sub_0x04_returns_nrc_12(self):
        state = _sim()
        resp = _req(state, bytes([SID_ECU_RESET, 0x04]))
        assert resp == _nrc(SID_ECU_RESET, NRC_SUB_FUNCTION_NOT_SUPPORTED)

    def test_ecu_reset_resets_session_to_default(self):
        """After ECUReset, session must be 0x01 (default)."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        assert state.session == SESSION_EXTENDED
        _req(state, bytes([SID_ECU_RESET, 0x01]))
        assert state.session == SESSION_DEFAULT, (
            f"ECUReset must reset session to default (0x01), "
            f"but session is still 0x{state.session:02X}")

    def test_ecu_reset_clears_security_unlock(self):
        """After ECUReset, security must be cleared."""
        state = _sim()
        state.session = SESSION_EXTENDED
        state.sec_unlocked[1] = True
        _req(state, bytes([SID_ECU_RESET, 0x01]))
        assert not state.sec_unlocked.get(1), "ECUReset must clear security unlock"

    def test_ecu_reset_too_short_pdu_nrc_13(self):
        state = _sim()
        resp = _req(state, bytes([SID_ECU_RESET]))
        assert resp == _nrc(SID_ECU_RESET, NRC_INCORRECT_MSG_LEN)


class TestReadDTCInfoEdgeCases:
    """ReadDTCInformation boundary cases and unsupported subfunctions."""

    def test_rdtc_sub_01_mask_0x00_returns_count_0(self):
        """Mask 0x00 matches no DTC status bits → count must be 0."""
        state = _sim()
        state.dtcs[0]['status'] = 0xFF  # all bits set
        resp = _req(state, bytes([SID_READ_DTC, 0x01, 0x00]))
        assert resp is not None and resp[0] == SID_READ_DTC + POSITIVE_RESPONSE_OFFSET
        count = (resp[4] << 8) | resp[5]
        assert count == 0, f"Mask 0x00 should match 0 DTCs, got {count}"

    def test_rdtc_sub_01_mask_0xff_returns_all_active(self):
        state = _sim()
        state.dtcs[0]['status'] = 0x08
        state.dtcs[1]['status'] = 0x00
        resp = _req(state, bytes([SID_READ_DTC, 0x01, 0xFF]))
        count = (resp[4] << 8) | resp[5]
        assert count == 1, f"One DTC with status 0x08 should match mask 0xFF, got {count}"

    def test_rdtc_sub_02_empty_when_all_clear(self):
        state = _sim()
        resp = _req(state, bytes([SID_READ_DTC, 0x02, 0xFF]))
        assert resp is not None
        # Response is [0x59, 0x02, mask] + DTC records; with all status=0x00 and mask=0xFF → no match
        assert resp == bytes([SID_READ_DTC + POSITIVE_RESPONSE_OFFSET, 0x02, 0xFF])

    def test_rdtc_unsupported_sub_0x0f_returns_nrc_12(self):
        """Sub=0x0F (reportSupportedDTC) — if not implemented, must return NRC 0x12."""
        state = _sim()
        resp = _req(state, bytes([SID_READ_DTC, 0x0F]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE, (
            f"Sub=0x0F must return NRC if not implemented, got {resp.hex()}")
        assert resp[2] == NRC_SUB_FUNCTION_NOT_SUPPORTED, (
            f"Expected NRC 0x12 for unsupported sub=0x0F, got 0x{resp[2]:02X}")

    def test_rdtc_unsupported_sub_0x11_returns_nrc_12(self):
        state = _sim()
        resp = _req(state, bytes([SID_READ_DTC, 0x11]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_SUB_FUNCTION_NOT_SUPPORTED

    def test_rdtc_too_short_pdu_nrc_13(self):
        state = _sim()
        resp = _req(state, bytes([SID_READ_DTC]))
        assert resp == _nrc(SID_READ_DTC, NRC_INCORRECT_MSG_LEN)

    def test_rdtc_sub_01_too_short_no_mask_byte_nrc_13(self):
        state = _sim()
        resp = _req(state, bytes([SID_READ_DTC, 0x01]))  # missing mask byte
        assert resp == _nrc(SID_READ_DTC, NRC_INCORRECT_MSG_LEN)
